      "term": "Transposition",
      "simpleDefinition": "The process of rearranging a formula to solve for a different unknown value.",
      "anchor": "The 'Golden Rule': whatever you do to one side of the equals sign, you must do to the other.",
      "misconception": "Moving a term to the other side without changing its operation (e.g., moving a multiplier as a multiplier instead of a divisor)."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Small numbers (powers) that show how many times a base number is multiplied by itself.",
      "anchor": "Using powers of 10 to represent kilo (10³) or milli (10⁻³).",
      "misconception": "Multiplying the base number by the index value (e.g., thinking 10² is 20 instead of 100)."
    },
    {
      "term": "Pythagoras’ Theorem",
      "simpleDefinition": "A mathematical rule stating that in a right-angled triangle, the square of the longest side equals the sum of the squares of the other two sides.",
      "anchor": "Calculating the hypotenuse of an impedance triangle.",
      "misconception": "Attempting to use this formula on triangles that do not have a 90-degree angle."
    },
    {
      "term": "Trigonometry (SOHCAHTOA)",
      "simpleDefinition": "The study of the relationships between the sides and angles of right-angled triangles.",
      "anchor": "Using Sine, Cosine, and Tangent to find phase angles in AC circuits.",
      "misconception": "Thinking trigonometry is only for physical geometry rather than invisible electrical properties like phase shift."
    },
    {
      "term": "Substitution",
      "simpleDefinition": "Replacing the letters in a formula with specific numerical values to calculate a result.",
      "anchor": "Swapping 'I' for 13 Amps in the formula P = V x I.",
      "misconception": "Treating letters as fixed labels rather than placeholders for changing values."
    },
    {
      "term": "Percentage",
      "simpleDefinition": "A way of expressing a number as a fraction of 100.",
      "anchor": "Checking if a voltage drop is within the 3% or 5% regulatory limits.",
      "misconception": "Believing that electrical percentages follow different mathematical rules than standard percentages."
    }
  ],
  "anchorPhrases": [
    "Whatever you do to one side, you must do to the other.",
    "SOHCAHTOA for finding angles and sides.",
    "Powers of 10 for scaling units.",
    "The Golden Rule of transposition."
  ],
  "misconceptionTargets": [
    "Moving a multiplier across the equals sign without changing it to a divisor.",
    "Multiplying the base by the exponent instead of squaring or cubing.",
    "Applying right-angle math to non-right-angled triangles.",
    "Confusing the base number with the index during calculation."
  ]
}

